                </div>\r\n                                </div>\r\n                                <div class=\"col-md-4\">\r\n                                    <div\r\n                                        v-show=\"form.unit_type_id != 'ZZ'\"\r\n                                        class=\"col-md-3 center-el-checkbox\"\r\n                                    >\r\n                                        <div class=\"form-group\">\r\n                                            <el-checkbox\r\n                                                v-model=\"form.lots_enabled\"\r\n                                                @change=\"changeLotsEnabled\"\r\n                                                >¿Maneja lotes?</el-checkbox\r\n                                            ><br />\r\n                                        </div>\r\n                                    </div>\r\n\r\n                                    <div\r\n                                        class=\"col-md-6\"\r\n                                        v-show=\"\r\n                                            form.unit_type_id != 'ZZ' &&\r\n                                                form.lots_enabled\r\n                                        \"\r\n                                    >\r\n                                        <div\r\n                                            class=\"form-group\"\r\n                                            :class=\"{\r\n                                                'has-danger': errors.lot_code\r\n                                            }\"\r\n                                        >\r\n                                            <label class=\"control-label\">\r\n                                                Código lote\r\n                                            </label>\r\n                                            <el-input v-model=\"form.lot_code\">\r\n                                                <i\r\n                                                    slot=\"prefix\"\r\n                                                    class=\"el-icon-edit-outline\"\r\n                                                ></i\r\n                                            ></el-input>\r\n                                            <small\r\n                                                class=\"text-danger\"\r\n                                                v-if=\"errors.lot_code\"\r\n                                                v-text=\"errors.lot_code[0]\"\r\n                                            ></small>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"d-flex\" v-if=\"configuration.promotions_sell\">\r\n                                <div class=\"col-md-3\">\r\n                                    <div\r\n                                        v-show=\"form.unit_type_id != 'ZZ'\"\r\n                                        class=\"col-md-6 center-el-checkbox\"\r\n                                    >\r\n                                        <div class=\"form-group\">\r\n                                            <el-checkbox v-model=\"form.is_promotion\"\r\n                                                \r\n                                                >¿Maneja Promocion ?</el-checkbox\r\n                                            ><br />\r\n                                        </div>\r\n                                        <el-input type=\"number\"  v-model=\"form.promotion_count\">\r\n                                                <i\r\n                                                    slot=\"prefix\"\r\n                                                    class=\"el-icon-edit-outline\"\r\n                                                ></i\r\n                                            ></el-input>\r\