ncelar]</a\r\n                                                >\r\n                                                <el-input\r\n                                                    v-if=\"\r\n                                                        form_brand.add == true\r\n                                                    \"\r\n                                                    v-model=\"form_brand.name\"\r\n                                                    dusk=\"item_code\"\r\n                                                    style=\"margin-bottom:1.5%;\"\r\n                                                >\r\n                                                    <i\r\n                                                        slot=\"prefix\"\r\n                                                        class=\"el-icon-edit-outline\"\r\n                                                    ></i\r\n                                                ></el-input>\r\n\r\n                                                <el-select\r\n                                                    v-if=\"\r\n                                                        form_brand.add == false\r\n                                                    \"\r\n                                                    v-model=\"form.brand_id\"\r\n                                                    filterable\r\n                                                    clearable\r\n                                                >\r\n                                                    <el-option\r\n                                                        v-for=\"option in brands\"\r\n                                                        :key=\"option.id\"\r\n                                                        :value=\"option.id\"\r\n                                                        :label=\"option.name\"\r\n                                                    ></el-option>\r\n                               