                              \"\r\n                                                    >[+ Agregar]</a\r\n                                                >\r\n                                            </h6>\r\n                                        </div>\r\n                                        <div\r\n                                            v-if=\"form.attributes.length > 0\"\r\n                                            class=\"col-md-12\"\r\n                                        >\r\n                                            <div class=\"table-responsive\">\r\n                                                <table class=\"table\">\r\n                                                    <thead>\r\n                                                        <tr>\r\n                                                            <th>Tipo</th>\r\n                                                            <th>Descripción</th>\r\n                                                            <th></th>\r\n                                                        </tr>\r\n                                                    </thead>\r\n                                                    <tbody>\r\n                                                        <tr\r\n                                                            v-for=\"(row,\r\n                                                            index) in form.attributes\"\r\n                                                            :key=\"index\"\r\n                                                        >\r\n                                                            <td>\r\n                                                                <el-select\r\n                                                                    v-model=\"\r\n                                                                        row.attribute_type_id\r\n                                                                    \"\r\n                                                                    filterable\r\n                                                                    @change=\"\r\n                                                                        changeAttributeType(\r\n                                                                            index\r\n                                                                        )\r\n                                                                    \"\r\n                                                                >\r\n                                                                    <el-option\r\n                                                                        v-for=\"option in attribute_types\"\r\n                                                                        :key=\"\r\n                                                                            option.id\r\n                                                                        \"\r\n                                                                        :value=\"\r\n                                                                            option.id\r\n                                                                        \"\r\n                                                                        :label=\"\r\n                                                                            option.description\r\n                                                                        \"\r\n                                                                    >\r\n                                                                    </el-option>\r\n                                                                </el-select>\r\n                                                            </td>\r\n                                                            <td>\r\n                                                                <el-input\r\n                                                                    v-model=\"\r\n                                                                        row.value\r\n                                                                    \"\r\n                                                                >\r\n                                                                    <i\r\n                                                                        slot=\"prefix\"\r\n                                                                        class=\"el-icon-edit-outline\"\r\n                                                                    ></i\r\n                                                                ></el-input>\r\n                                                            </td>\r\n                                                            <td>\r\n                                                                <button\r\n                                                                    type=\"button\"\r\n                                                                    class=\"btn btn-danger\"\r\n                                                                    @click.prevent=\"\r\n                                                                        clickRemoveAttribute(\r\n                                                                            index\r\n                                                                        )\r\n                                                                    \"\r\n                                                                >\r\n                                                                    x\r\n                                                                </button>\r\n                                                            </td>\r\n                                                        </tr>\r\n                                                    </tbody>\r\n                                                </table>\r\n                                            </div>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                    </el-tab-pane>\r\n                    <el-tab-pane\r\n                        v-if=\"form.unit_type_id != 'ZZ'\"\r\n                        label=\"Almacenes\"\r\n                    >\r\n                        <div class=\"row\">\r\n                            <div class=\"col-12\">\r\n                                <h5 class=\"separator-title mt-0\">\r\n                                    Precios por almacén\r\n                                </h5>\r\n                                <table>\r\n                                    <tbody>\r\n                                        <tr\r\n                                            v-for=\"w in form.warehouse_prices\"\r\n                                            :key=\"w.id\"\r\n                                        >\r\n                                            <td width=\"80%\">\r\n                                                <h3>{{ w.warehouse }}</h3>\r\n                                            </td>\r\n                                            <td>\r\n                                                <el-input\r\n                                                    v-model=\"w.price\"\r\n                                                    @input=\"$forceUpdate()\"\r\n                                                    placeholder=\"Precio de almacen\"\r\n                                                >\r\n                                                </el-input>\r\n                                            </td>\r\n                                        </tr>\r\n                                    </tbody>\r\n                                </table>\r\n                            </div>\r\n                        </div>\r\n                    </el-tab-pane>\r\n                    <el-tab-pane label=\"Lista de Precios\">\r\n                        <div class=\"row\">\r\n                            <div\r\n                                v-show=\"form.unit_type_id != 'ZZ'\"\r\n                                class=\"col-md-12\"\r\n                            >\r\n                                <h6 class=\"separator-title \">\r\n                                    Listado de precios\r\n                                    <el-tooltip\r\n                                        class=\"item\"\r\n                                        effect=\"dark\"\r\n                                        content=\"Aplica para realizar compra/venta en presentacion de diferentes precios y/o cantidades\"\r\n                                        placement=\"top\"\r\n                                    >\r\n                                        <i class=\"fa fa-info-circle\"></i>\r\n                                    </el-tooltip>\r\n                                    <a\r\n                                        href=\"#\"\r\n                                        class=\"control-label font-weight-bold text-info\"\r\n                                        @click=\"clickAddRow\"\r\n                                    >\r\n                                        [ + Nuevo]</a\r\n                                    >\r\n                                </h6>\r\n                            </div>\r\n\r\n                            <div\r\n                                v-show=\"form.unit_type_id != 'ZZ'\"\r\n                                class=\"col-md-12\"\r\n                                v-if=\"form.item_unit_types.length > 0\"\r\n                            >\r\n                                <div class=\"table-responsive\">\r\n                                    <table class=\"table\">\r\n                                        <thead>\r\n                                            <tr>\r\n        