y_unit }}\r\n                                                    </td>\r\n                                                    <td class=\"text-center\">\r\n                                                        <el-input\r\n                                                            v-model=\"row.price2\"\r\n                                                            @input=\"\r\n                                                                undToTotal(\r\n                                                                    index,\r\n                                                                    row.price2,\r\n                                                                    row.quantity_unit\r\n                                                                )\r\n                                                            \"\r\n                                                        >\r\n                                                            <i\r\n                                                                slot=\"prefix\"\r\n                                                                class=\"el-icon-edit-outline\"\r\n                                                            ></i\r\n                                                        ></el-input>\r\n                                                    </td>\r\n                                                    <td class=\"text-center\">\r\n                                                        <el-input\r\n                                                            v-model=\"row.total\"\r\n                                                            @input=\"\r\n                                                                totalToUnd(\r\n                                                                    index,\r\n                                                                    row.total,\r\n                                                                    row.quantity_unit\r\n                                                                )\r\n                                                            \"\r\n                                                        >\r\n                                                            <i\r\n                                                                slot=\"prefix\"\r\n                                                                class=\"el-icon-edit-outline\"\r\n                                                            ></i\r\n                                                        ></el-input>\r\n\r\n                                                        <!-- <td class=\"text-center\">\r\n                                                        Precio\r\n                                                        {{ row.price_default }}\r\n                                                    </td> -->\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <el-select\r\n                                                            clearable\r\n                                                            v-model=\"\r\n                                                                row.warehouse_id\r\n                                                            \"\r\n                                                        >\r\n                                                            <el-option\r\n                                                                v-for=\"w in warehouses\"\r\n                                                                :key=\"w.id\"\r\n                                                                :value=\"w.id\"\r\n                                                                :label=\"\r\n                                                                    w.description\r\n                                                                \"\r\n                                                            ></el-option>\r\n                                                        </el-select>\r\n                                                    </td>\r\n                                                    <td>\r\n                                                        <el-checkbox\r\n                                                            v-model=\"\r\n                                                                row.selected\r\n                                                            \"\r\n                                                            @change=\"\r\n                                                                selectedMax(\r\n                                                                    index\r\n                                                                )\r\n                                                            \"\r\n                                                        ></el-checkbox>\r\n                                                    </td>\r\n\r\n                                                    <td\r\n                                                        class=\"series-table-actions text-end\"\r\n                                                    >\r\n                                                        <button\r\n                                                            type=\"button\"\r\n                                                            class=\"btn waves-effect waves-light btn-sm btn-danger\"\r\n                                                            @click.prevent=\"\r\n                                                                clickDelete(\r\n                                                                    row.id\r\n                                                                )\r\n                                                            \"\r\n                                                        >\r\n                  